#nullable enable
using System;
using System.Text.Json;
using System.Text.Json.Serialization;
using Adyen.Core;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Adyen.Test.Core
{
    /// <summary>
    /// Tests for the standalone IEnum class pattern (generated by modelEnum.mustache).
    /// Covers IEX-3037 (forward-compatibility) and GitHub issue #1612 (NullReferenceException).
    /// </summary>
    [TestClass]
    public class StandaloneEnumTest
    {
        // ─── Deserialization: known values ────────────────────────────────────────

        [TestMethod]
        public void Given_JsonDeserialization_When_KnownValue_Then_Returns_CorrectInstance()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum? result = JsonSerializer.Deserialize<ExampleStandaloneEnum>("\"active\"", options);
            Assert.AreEqual(ExampleStandaloneEnum.Active, result);
            Assert.AreEqual("active", result?.Value);
        }

        [TestMethod]
        public void Given_JsonDeserialization_When_AnotherKnownValue_Then_Returns_CorrectInstance()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum? result = JsonSerializer.Deserialize<ExampleStandaloneEnum>("\"inactive\"", options);
            Assert.AreEqual(ExampleStandaloneEnum.Inactive, result);
        }

        // ─── Deserialization: unknown values are preserved ────────────────────────

        [TestMethod]
        public void Given_JsonDeserialization_When_UnknownValue_Then_PreservesRawString()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum? result = JsonSerializer.Deserialize<ExampleStandaloneEnum>("\"future-value\"", options);
            Assert.IsNotNull(result);
            Assert.AreEqual("future-value", result!.Value);
            Assert.AreNotEqual(ExampleStandaloneEnum.Active, result);
        }

        [TestMethod]
        public void Given_JsonDeserialization_When_UnknownValue_Then_DoesNotThrow()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum? result = null;
            var ex = CaptureException(() =>
                result = JsonSerializer.Deserialize<ExampleStandaloneEnum>("\"completely-unknown-status\"", options));
            Assert.IsNull(ex);
            Assert.IsNotNull(result);
            Assert.AreEqual("completely-unknown-status", result!.Value);
        }

        // ─── Deserialization: null ────────────────────────────────────────────────

        [TestMethod]
        public void Given_JsonDeserialization_When_NullJson_Then_ReturnsNull()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum? result = JsonSerializer.Deserialize<ExampleStandaloneEnum>("null", options);
            Assert.IsNull(result);
        }

        // ─── Serialization: known values ─────────────────────────────────────────

        [TestMethod]
        public void Given_JsonSerialization_When_KnownValue_Then_WritesCorrectString()
        {
            var options = BuildOptions();
            string json = JsonSerializer.Serialize(ExampleStandaloneEnum.Active, options);
            Assert.AreEqual("\"active\"", json);
        }

        // ─── Serialization: unknown values are preserved ─────────────────────────

        [TestMethod]
        public void Given_JsonSerialization_When_UnknownValue_Then_PreservesRawString()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum unknown = (ExampleStandaloneEnum)"new-future-value";
            string json = JsonSerializer.Serialize(unknown, options);
            Assert.AreEqual("\"new-future-value\"", json);
        }

        // ─── Serialization: null ─────────────────────────────────────────────────

        [TestMethod]
        public void Given_JsonSerialization_When_NullValue_Then_WritesJsonNull()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum? value = null;
            string json = JsonSerializer.Serialize(value, options);
            Assert.AreEqual("null", json);
        }

        // ─── Round-trip: known values ─────────────────────────────────────────────

        [TestMethod]
        public void Given_RoundTrip_When_KnownValue_Then_PreservesIdentity()
        {
            var options = BuildOptions();
            string serialized = JsonSerializer.Serialize(ExampleStandaloneEnum.Active, options);
            ExampleStandaloneEnum? deserialized = JsonSerializer.Deserialize<ExampleStandaloneEnum>(serialized, options);
            Assert.AreEqual(ExampleStandaloneEnum.Active, deserialized);
        }

        // ─── Round-trip: unknown values ───────────────────────────────────────────

        [TestMethod]
        public void Given_RoundTrip_When_UnknownValue_Then_PreservesRawString()
        {
            var options = BuildOptions();
            ExampleStandaloneEnum original = (ExampleStandaloneEnum)"brand-new-value";
            string serialized = JsonSerializer.Serialize(original, options);
            ExampleStandaloneEnum? deserialized = JsonSerializer.Deserialize<ExampleStandaloneEnum>(serialized, options);
            Assert.IsNotNull(deserialized);
            Assert.AreEqual("brand-new-value", deserialized!.Value);
        }

        // ─── Equality ────────────────────────────────────────────────────────────

        [TestMethod]
        public void Given_Equality_When_SameKnownValues_Then_Equal()
        {
            Assert.AreEqual(ExampleStandaloneEnum.Active, ExampleStandaloneEnum.Active);
            Assert.IsTrue(ExampleStandaloneEnum.Active == ExampleStandaloneEnum.Active);
        }

        [TestMethod]
        public void Given_Equality_When_DifferentValues_Then_NotEqual()
        {
            Assert.AreNotEqual(ExampleStandaloneEnum.Active, ExampleStandaloneEnum.Inactive);
            Assert.IsTrue(ExampleStandaloneEnum.Active != ExampleStandaloneEnum.Inactive);
        }

        [TestMethod]
        public void Given_Equality_When_UnknownValuesWithSameString_Then_Equal()
        {
            ExampleStandaloneEnum a = (ExampleStandaloneEnum)"custom";
            ExampleStandaloneEnum b = (ExampleStandaloneEnum)"custom";
            Assert.AreEqual(a, b);
            Assert.IsTrue(a == b);
        }

        [TestMethod]
        public void Given_Equality_When_CaseInsensitive_Then_Equal()
        {
            ExampleStandaloneEnum lower = (ExampleStandaloneEnum)"active";
            ExampleStandaloneEnum upper = (ExampleStandaloneEnum)"ACTIVE";
            Assert.AreEqual(lower, upper);
            Assert.IsTrue(lower == upper);
        }

        [TestMethod]
        public void Given_Equality_When_NullComparison_Then_Correct()
        {
            ExampleStandaloneEnum? nullEnum = null;
            Assert.AreNotEqual(ExampleStandaloneEnum.Active, nullEnum);
            Assert.AreEqual(nullEnum, nullEnum);
        }

        // ─── FromStringOrDefault ──────────────────────────────────────────────────

        [TestMethod]
        public void Given_FromStringOrDefault_When_KnownValue_Then_ReturnsStaticInstance()
        {
            Assert.AreEqual(ExampleStandaloneEnum.Active, ExampleStandaloneEnum.FromStringOrDefault("active"));
            Assert.AreEqual(ExampleStandaloneEnum.Inactive, ExampleStandaloneEnum.FromStringOrDefault("inactive"));
        }

        [TestMethod]
        public void Given_FromStringOrDefault_When_UnknownValue_Then_ReturnsNull()
        {
            Assert.IsNull(ExampleStandaloneEnum.FromStringOrDefault("not-in-list"));
        }

        [TestMethod]
        public void Given_FromStringOrDefault_When_NullInput_Then_ReturnsNull()
        {
            Assert.IsNull(ExampleStandaloneEnum.FromStringOrDefault(null));
        }

        // ─── ToJsonValue ──────────────────────────────────────────────────────────

        [TestMethod]
        public void Given_ToJsonValue_When_KnownEnum_Then_ReturnsString()
        {
            Assert.AreEqual("active", ExampleStandaloneEnum.ToJsonValue(ExampleStandaloneEnum.Active));
            Assert.AreEqual("inactive", ExampleStandaloneEnum.ToJsonValue(ExampleStandaloneEnum.Inactive));
        }

        [TestMethod]
        public void Given_ToJsonValue_When_Null_Then_ReturnsNull()
        {
            Assert.IsNull(ExampleStandaloneEnum.ToJsonValue(null));
        }

        [TestMethod]
        public void Given_ToJsonValue_When_UnknownValue_Then_ReturnsRawString()
        {
            ExampleStandaloneEnum unknown = (ExampleStandaloneEnum)"new-api-value";
            Assert.AreEqual("new-api-value", ExampleStandaloneEnum.ToJsonValue(unknown));
        }

        // ─── Model: required enum with known value ────────────────────────────────

        [TestMethod]
        public void Given_ModelDeserialization_When_RequiredEnumIsKnown_Then_DeserializesCorrectly()
        {
            var options = BuildOptions();
            string json = @"{ ""status"": ""active"", ""name"": ""test"" }";
            ExampleModelWithRequiredEnum? result = JsonSerializer.Deserialize<ExampleModelWithRequiredEnum>(json, options);
            Assert.IsNotNull(result);
            Assert.AreEqual(ExampleStandaloneEnum.Active, result!.Status);
        }

        // ─── Model: required enum with UNKNOWN value — GitHub issue #1612 ─────────

        [TestMethod]
        public void Given_ModelDeserialization_When_RequiredEnumIsUnknown_Then_DoesNotThrow()
        {
            var options = BuildOptions();
            string json = @"{ ""status"": ""future-status-not-yet-in-sdk"", ""name"": ""test"" }";
            ExampleModelWithRequiredEnum? result = null;
            var ex = CaptureException(() =>
                result = JsonSerializer.Deserialize<ExampleModelWithRequiredEnum>(json, options));
            Assert.IsNull(ex, $"Should not throw. Got: {ex?.Message}");
            Assert.IsNotNull(result);
            Assert.IsNotNull(result!.Status);
            Assert.AreEqual("future-status-not-yet-in-sdk", result.Status.Value);
        }

        // ─── Model: optional enum with null ──────────────────────────────────────

        [TestMethod]
        public void Given_ModelDeserialization_When_OptionalEnumIsNull_Then_PropertyIsNull()
        {
            var options = BuildOptions();
            string json = @"{ ""optionalStatus"": null, ""name"": ""test"" }";
            ExampleModelWithOptionalEnum? result = JsonSerializer.Deserialize<ExampleModelWithOptionalEnum>(json, options);
            Assert.IsNotNull(result);
            Assert.IsNull(result!.OptionalStatus);
        }

        // ─── Model: optional enum with unknown value ──────────────────────────────

        [TestMethod]
        public void Given_ModelDeserialization_When_OptionalEnumIsUnknown_Then_PreservesValue()
        {
            var options = BuildOptions();
            string json = @"{ ""optionalStatus"": ""new-value"", ""name"": ""test"" }";
            ExampleModelWithOptionalEnum? result = JsonSerializer.Deserialize<ExampleModelWithOptionalEnum>(json, options);
            Assert.IsNotNull(result);
            Assert.IsNotNull(result!.OptionalStatus);
            Assert.AreEqual("new-value", result.OptionalStatus!.Value);
        }

        // ─── Model serialization round-trip with unknown value ────────────────────

        [TestMethod]
        public void Given_ModelRoundTrip_When_UnknownEnumValue_Then_PreservesValue()
        {
            var options = BuildOptions();
            string originalJson = @"{ ""status"": ""future-status"", ""name"": ""test"" }";
            ExampleModelWithRequiredEnum? deserialized = JsonSerializer.Deserialize<ExampleModelWithRequiredEnum>(originalJson, options);
            string reserialized = JsonSerializer.Serialize(deserialized, options);
            Assert.IsTrue(reserialized.Contains("\"future-status\""),
                $"Expected raw string preserved in JSON. Got: {reserialized}");
        }

        // ─── Implicit string conversion ───────────────────────────────────────────

        [TestMethod]
        public void Given_ImplicitConversion_When_FromString_Then_CreatesInstance()
        {
            ExampleStandaloneEnum? result = "active";
            Assert.AreEqual(ExampleStandaloneEnum.Active, result);
        }

        [TestMethod]
        public void Given_ImplicitConversion_When_NullString_Then_ReturnsNull()
        {
            ExampleStandaloneEnum? result = (string?)null;
            Assert.IsNull(result);
        }

        [TestMethod]
        public void Given_ImplicitConversion_When_ToStringFromEnum_Then_ReturnsValue()
        {
            string? result = ExampleStandaloneEnum.Active;
            Assert.AreEqual("active", result);
        }

        // ─── helpers ─────────────────────────────────────────────────────────────

        private static JsonSerializerOptions BuildOptions()
        {
            var options = new JsonSerializerOptions();
            options.Converters.Add(new ExampleStandaloneEnum.ExampleStandaloneEnumJsonConverter());
            options.Converters.Add(new ExampleModelWithRequiredEnum.ExampleModelWithRequiredEnumJsonConverter());
            options.Converters.Add(new ExampleModelWithOptionalEnum.ExampleModelWithOptionalEnumJsonConverter());
            return options;
        }

        private static Exception? CaptureException(Action action)
        {
            try { action(); return null; }
            catch (Exception e) { return e; }
        }
    }

    // ═══════════════════════════════════════════════════════════════════════════
    // ExampleStandaloneEnum - mirrors output of the new modelEnum.mustache
    // ═══════════════════════════════════════════════════════════════════════════

    [JsonConverter(typeof(ExampleStandaloneEnum.ExampleStandaloneEnumJsonConverter))]
    internal class ExampleStandaloneEnum : IEnum
    {
        public string? Value { get; set; }

        public static readonly ExampleStandaloneEnum Active = new("active");
        public static readonly ExampleStandaloneEnum Inactive = new("inactive");

        private ExampleStandaloneEnum(string? value) { Value = value; }

        public static implicit operator ExampleStandaloneEnum?(string? value) =>
            value == null ? null : new ExampleStandaloneEnum(value);

        public static implicit operator string?(ExampleStandaloneEnum? option) => option?.Value;

        public static bool operator ==(ExampleStandaloneEnum? left, ExampleStandaloneEnum? right) =>
            string.Equals(left?.Value, right?.Value, StringComparison.OrdinalIgnoreCase);

        public static bool operator !=(ExampleStandaloneEnum? left, ExampleStandaloneEnum? right) =>
            !string.Equals(left?.Value, right?.Value, StringComparison.OrdinalIgnoreCase);

        public override bool Equals(object? obj) =>
            obj is ExampleStandaloneEnum other && string.Equals(Value, other.Value, StringComparison.OrdinalIgnoreCase);

        public override int GetHashCode() => StringComparer.OrdinalIgnoreCase.GetHashCode(Value ?? string.Empty);

        public override string ToString() => Value ?? string.Empty;

        public static ExampleStandaloneEnum? FromStringOrDefault(string? value) => value switch
        {
            "active" => Active,
            "inactive" => Inactive,
            _ => null,
        };

        public static string? ToJsonValue(ExampleStandaloneEnum? value)
        {
            if (value == null) return null;
            if (value == Active) return "active";
            if (value == Inactive) return "inactive";
            return value.Value;
        }

        public class ExampleStandaloneEnumJsonConverter : JsonConverter<ExampleStandaloneEnum>
        {
            public override ExampleStandaloneEnum? Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
            {
                string? rawValue = reader.GetString();
                return rawValue == null
                    ? null
                    : ExampleStandaloneEnum.FromStringOrDefault(rawValue) ?? new ExampleStandaloneEnum(rawValue);
            }

            public override void Write(Utf8JsonWriter writer, ExampleStandaloneEnum value, JsonSerializerOptions options)
            {
                writer.WriteStringValue(ExampleStandaloneEnum.ToJsonValue(value));
            }
        }
    }

    // ═══════════════════════════════════════════════════════════════════════════
    // ExampleModelWithRequiredEnum - simulates a generated model with a required
    // standalone enum property. Tests the GitHub issue #1612 regression pattern.
    // ═══════════════════════════════════════════════════════════════════════════

    internal class ExampleModelWithRequiredEnum
    {
        [JsonPropertyName("status")]
        public ExampleStandaloneEnum Status { get; set; } = null!;

        [JsonPropertyName("name")]
        public string? Name { get; set; }

        internal class ExampleModelWithRequiredEnumJsonConverter : JsonConverter<ExampleModelWithRequiredEnum>
        {
            public override ExampleModelWithRequiredEnum Read(ref Utf8JsonReader utf8JsonReader, Type typeToConvert, JsonSerializerOptions jsonSerializerOptions)
            {
                int currentDepth = utf8JsonReader.CurrentDepth;

                if (utf8JsonReader.TokenType != JsonTokenType.StartObject)
                    throw new JsonException();

                JsonTokenType startingTokenType = utf8JsonReader.TokenType;

                ExampleStandaloneEnum? status = null;
                bool statusSet = false;
                string? name = null;

                while (utf8JsonReader.Read())
                {
                    if (startingTokenType == JsonTokenType.StartObject
                        && utf8JsonReader.TokenType == JsonTokenType.EndObject
                        && currentDepth == utf8JsonReader.CurrentDepth)
                        break;

                    if (utf8JsonReader.TokenType == JsonTokenType.PropertyName
                        && currentDepth == utf8JsonReader.CurrentDepth - 1)
                    {
                        string? propertyName = utf8JsonReader.GetString();
                        utf8JsonReader.Read();

                        switch (propertyName)
                        {
                            case "status":
                                string? rawValue = utf8JsonReader.GetString();
                                // New pattern from JsonConverter.mustache: FromStringOrDefault ?? implicit cast
                                // This preserves unknown values instead of returning null.
                                status = ExampleStandaloneEnum.FromStringOrDefault(rawValue) ?? (ExampleStandaloneEnum?)rawValue;
                                statusSet = true;
                                break;
                            case "name":
                                name = utf8JsonReader.GetString();
                                break;
                            default:
                                break;
                        }
                    }
                }

                if (!statusSet)
                    throw new ArgumentException("Property is required for class ExampleModelWithRequiredEnum.", nameof(status));

                var model = new ExampleModelWithRequiredEnum();
                // New pattern from JsonConverter.mustache: no .Value unwrap — IEnum is a reference type
                model.Status = status!;
                model.Name = name;
                return model;
            }

            public override void Write(Utf8JsonWriter writer, ExampleModelWithRequiredEnum model, JsonSerializerOptions jsonSerializerOptions)
            {
                writer.WriteStartObject();
                if (model.Status != null)
                    writer.WriteString("status", ExampleStandaloneEnum.ToJsonValue(model.Status));
                if (model.Name != null)
                    writer.WriteString("name", model.Name);
                writer.WriteEndObject();
            }
        }
    }

    // ═══════════════════════════════════════════════════════════════════════════
    // ExampleModelWithOptionalEnum - simulates a generated model with an optional
    // standalone enum property.
    // ═══════════════════════════════════════════════════════════════════════════

    internal class ExampleModelWithOptionalEnum
    {
        [JsonPropertyName("optionalStatus")]
        public ExampleStandaloneEnum? OptionalStatus { get; set; }

        [JsonPropertyName("name")]
        public string? Name { get; set; }

        internal class ExampleModelWithOptionalEnumJsonConverter : JsonConverter<ExampleModelWithOptionalEnum>
        {
            public override ExampleModelWithOptionalEnum Read(ref Utf8JsonReader utf8JsonReader, Type typeToConvert, JsonSerializerOptions jsonSerializerOptions)
            {
                int currentDepth = utf8JsonReader.CurrentDepth;

                if (utf8JsonReader.TokenType != JsonTokenType.StartObject)
                    throw new JsonException();

                JsonTokenType startingTokenType = utf8JsonReader.TokenType;

                ExampleStandaloneEnum? optionalStatus = null;
                bool optionalStatusSet = false;
                string? name = null;

                while (utf8JsonReader.Read())
                {
                    if (startingTokenType == JsonTokenType.StartObject
                        && utf8JsonReader.TokenType == JsonTokenType.EndObject
                        && currentDepth == utf8JsonReader.CurrentDepth)
                        break;

                    if (utf8JsonReader.TokenType == JsonTokenType.PropertyName
                        && currentDepth == utf8JsonReader.CurrentDepth - 1)
                    {
                        string? propertyName = utf8JsonReader.GetString();
                        utf8JsonReader.Read();

                        switch (propertyName)
                        {
                            case "optionalStatus":
                                string? rawValue = utf8JsonReader.GetString();
                                optionalStatus = ExampleStandaloneEnum.FromStringOrDefault(rawValue) ?? (ExampleStandaloneEnum?)rawValue;
                                optionalStatusSet = true;
                                break;
                            case "name":
                                name = utf8JsonReader.GetString();
                                break;
                            default:
                                break;
                        }
                    }
                }

                var model = new ExampleModelWithOptionalEnum();
                if (optionalStatusSet)
                    model.OptionalStatus = optionalStatus;
                model.Name = name;
                return model;
            }

            public override void Write(Utf8JsonWriter writer, ExampleModelWithOptionalEnum model, JsonSerializerOptions jsonSerializerOptions)
            {
                writer.WriteStartObject();
                if (model.OptionalStatus != null)
                {
                    var rawValue = ExampleStandaloneEnum.ToJsonValue(model.OptionalStatus);
                    if (rawValue != null)
                        writer.WriteString("optionalStatus", rawValue);
                    else
                        writer.WriteNull("optionalStatus");
                }
                if (model.Name != null)
                    writer.WriteString("name", model.Name);
                writer.WriteEndObject();
            }
        }
    }
}
